if (!msg.payload) {
    node.error("Pas de réponse de l'API");
    msg.payload = { error: "No response" };
    return [null, msg];
}

if (msg.statusCode === 401) {
    node.error("Clé API invalide");
    msg.payload = { error: "API Key invalid" };
    return [null, msg];
}

if (msg.payload.cod && msg.payload.cod !== "200" && msg.payload.cod !== 200) {
    node.error("Erreur API: " + (msg.payload.message || msg.payload.cod));
    msg.payload = { error: msg.payload.message || "API Error", details: msg.payload };
    return [null, msg];
}

if (!msg.payload.daily || !Array.isArray(msg.payload.daily)) {
    node.error("Structure de données invalide");
    msg.payload = { error: "Invalid data structure", received: msg.payload };
    return [null, msg];
}

if (!msg.payload.hourly || !Array.isArray(msg.payload.hourly)) {
    node.error("Structure de données invalide");
    msg.payload = { error: "Invalid data structure", received: msg.payload };
    return [null, msg];
}

return [msg, null];

const dailyData = msg.payload.daily;
const hourlyData = msg.payload.hourly;

const tomorrow = dailyData[1];
const now = new Date();
const tomorrowDate = new Date(now);
tomorrowDate.setDate(tomorrowDate.getDate() + 1);
tomorrowDate.setHours(0, 0, 0, 0);

const tomorrowEnd = new Date(tomorrowDate);
tomorrowEnd.setHours(23, 59, 59, 999);

const tomorrowHourly = hourlyData.filter(h => {
    const hourDate = new Date(h.dt * 1000);
    return hourDate >= tomorrowDate && hourDate <= tomorrowEnd;
});

let sunHours = 0;
let totalCloudCover = 0;
let totalUVI = 0;
let count = 0;
let avgTemp = 0;

tomorrowHourly.forEach(hour => {
    const hourTime = new Date(hour.dt * 1000).getHours();
    if (hourTime >= 10 && hourTime <= 15) {
        const clouds = hour.clouds || 0;
        const sunPercent = 100 - clouds;
        sunHours += (sunPercent / 100);
        totalCloudCover += clouds;
        totalUVI += hour.uvi || 0;
        avgTemp += hour.temp;
        count++;
    }
});

const avgCloudCover = count > 0 ? totalCloudCover / count : 100;
const sunshinePercent = 100 - avgCloudCover;
avgTemp = count > 0 ? avgTemp / count : 0;
const avgUVI = count > 0 ? totalUVI / count : 0;

const sunrise = new Date(tomorrow.sunrise * 1000);
const sunset = new Date(tomorrow.sunset * 1000);
const daylightHours = (sunset - sunrise) / 3600000;

const installedPower = 9.3;
const efficiencyFactor = 0.65;
const uviBonus = Math.min(avgUVI / 10, 0.15);
const adjustedEfficiency = efficiencyFactor * (1 + uviBonus);
const estimatedProduction = (sunHours * installedPower * adjustedEfficiency).toFixed(2);

let recommendation = "";
let chargeStrategy = "";

if (sunshinePercent > 70 && avgUVI > 3) {
    recommendation = "☀️ Excellentes conditions solaires";
    chargeStrategy = "Ne pas charger ce soir - Production max demain";
} else if (sunshinePercent > 50) {
    recommendation = "🌤️ Bonnes conditions";
    chargeStrategy = "Charge légère si batteries < 50%";
} else if (sunshinePercent > 30) {
    recommendation = "⛅ Conditions moyennes";
    chargeStrategy = "Charge modérée recommandée";
} else {
    recommendation = "☁️ Conditions faibles";
    chargeStrategy = "⚠️ CHARGER BATTERIES À FOND CE SOIR";
}

const result = {
    date: tomorrowDate.toLocaleDateString('fr-FR'),
    sunshinePercent: Math.round(sunshinePercent),
    sunHours: sunHours.toFixed(1),
    daylightHours: daylightHours.toFixed(1),
    estimatedProduction: estimatedProduction,
    avgTemperature: avgTemp.toFixed(1),
    avgUVI: avgUVI.toFixed(1),
    maxUVI: tomorrow.uvi.toFixed(1),
    sunrise: sunrise.toLocaleTimeString('fr-FR', {hour: '2-digit', minute:'2-digit'}),
    sunset: sunset.toLocaleTimeString('fr-FR', {hour: '2-digit', minute:'2-digit'}),
    recommendation: recommendation,
    chargeStrategy: chargeStrategy,
    dataPoints: count,
    humidity: tomorrow.humidity,
    windSpeed: tomorrow.wind_speed.toFixed(1)
};

global.set('weather_forecast', result);

msg.payload = result;
return msg;

const d = msg.payload;

const message = `☀️ PRÉVISIONS SOLAIRES - ${d.date}

${d.recommendation}
🌤️ Ensoleillement: ${d.sunshinePercent}%
⏱️ Heures production: ${d.sunHours}h / ${d.daylightHours}h jour
⚡ Production estimée: ${d.estimatedProduction} kWh

🌡️ Température: ${d.avgTemperature}°C
☀️ UV Index: ${d.avgUVI} (max: ${d.maxUVI})
💧 Humidité: ${d.humidity}%
💨 Vent: ${d.windSpeed} m/s
🌅 Lever: ${d.sunrise} | Coucher: ${d.sunset}

🔋 STRATÉGIE BATTERIE:
${d.chargeStrategy}`;

msg.payload = message;
return msg;

let history = global.get('weather_history') || [];

history.unshift({
    timestamp: new Date(),
    forecast: msg.payload
});

if (history.length > 7) {
    history = history.slice(0, 7);
}

global.set('weather_history', history);

return msg;

const forecast = global.get('weather_forecast') || null;

if (forecast) {
    msg.payload = forecast;
    return msg;
} else {
    node.error("Aucune prévision disponible");
    return null;
}
